class SmoothDragHelper:
    """Provides smooth drag animation for windows and widgets."""
    def __init__(self, widget):
        self.widget = widget
        self.drag_pos = None
        self.animation = None
        self.is_dragging = False
    def start_drag(self, global_pos):
        """Initialize drag state."""
        self.is_dragging = True
        self.drag_pos = global_pos - self.widget.frameGeometry().topLeft()
    def update_drag(self, global_pos):
        """Update position during drag without animation."""
        if self.drag_pos is not None and self.is_dragging:
                self.widget.move(global_pos - self.drag_pos)
    def end_drag(self):
        """End drag state."""
        self.is_dragging = False
        self.drag_pos = None
    def smooth_move_to(self, target_pos, duration=150):
        """Animate window to target position smoothly."""
        if self.animation:
            self.animation.stop()
        self.animation = QPropertyAnimation(self.widget, b'geometry')
        self.animation.setDuration(duration)
        self.animation.setEasingCurve(QEasingCurve.OutCubic)
        current_geo = self.widget.frameGeometry()
        target_geo = current_geo
        target_geo.moveTo(target_pos)
        self.animation.setStartValue(current_geo)
        self.animation.setEndValue(target_geo)
        self.animation.start()
