class _ResizeGrip(QLabel):
    """Bottom-right corner resize handle for KeybindInfoWindow."""
    def __init__(self, target, parent=None):
        super().__init__(parent)
        self._target = target
        self._resizing = False
        self._start_pos = None
        self._start_size = None
        px = _make_resize_pixmap(22)
        self.setPixmap(px)
        self.setFixedSize(26, 26)
        self.setAlignment(Qt.AlignCenter)
        self.setStyleSheet('background: transparent; border: 1px solid #2A3B4D; border-radius: 4px;')
        self.setCursor(Qt.SizeFDiagCursor)
        self.setToolTip('Drag to resize')
    def mousePressEvent(self, e):
        if e.button() == Qt.LeftButton:
            self._resizing = True
            self._start_pos = e.globalPos()
            self._start_size = self._target.size()
            e.accept()
    def mouseMoveEvent(self, e):
        if self._resizing and e.buttons() == Qt.LeftButton:
                delta = e.globalPos() - self._start_pos
                new_w = max(200, self._start_size.width() + delta.x())
                new_h = max(180, self._start_size.height() + delta.y())
                self._target.resize(new_w, new_h)
                e.accept()
    def mouseReleaseEvent(self, e):
        self._resizing = False
        e.accept()
